// TCP connection handler that safely deserializes incoming data
class ConnectionHandlerActor(processor: ActorRef) extends Actor with ActorLogging {
  import Tcp._

  private var buffer = ByteString.empty

  override def receive: Receive = {
    case Received(data) =>
      buffer ++= data
