    case PeerClosed =>
      log.info("Peer closed connection")
      context.stop(self)

    case ErrorClosed(cause) =>
      log.warning(s"Connection error: $cause")
      context.stop(self)
  }

  private def processBuffer(): Unit = {
    // Simple length-prefixed framing: first 4 bytes = message length
    if (buffer.length >= 4) {
      val length = ((buffer(0) & 0xFF) << 24) |
        ((buffer(1) & 0xFF) << 16) |
        ((buffer(2) & 0xFF) << 8) |
        (buffer(3) & 0xFF)

