          case Left(error) =>
            log.warning(s"Failed to deserialize message from untrusted source: $error")
          // Do NOT fall back to Java ObjectInputStream - that would be unsafe
        }

        // Process remaining data in buffer
        if (buffer.nonEmpty) processBuffer()
      }
    }
  }
}

// TCP server actor
class TcpServerActor(host: String, port: Int, processor: ActorRef) extends Actor with ActorLogging {
  import Tcp._
  import context.system

  IO(Tcp) ! Bind(self, new InetSocketAddress(host, port))

  override def receive: Receive = {
    case Bound(localAddress) =>
      log.info(s"Server bound to $localAddress")

    case CommandFailed(_: Bind) =>
      log.error(s"Failed to bind to $host:$port")
      context.stop(self)

    case Connected(remote, _) =>
      log.info(s"New connection from $remote")
      val handler = context.actorOf(Props(new ConnectionHandlerActor(processor)))
      sender() ! Register(handler)
  }
}

// TCP client for sending messages
class TcpClientActor(host: String, port: Int) extends Actor with ActorLogging {
  import Tcp._
  import context.system

  IO(Tcp) ! Connect(new InetSocketAddress(host, port))

  override def receive: Receive = {
    case CommandFailed(_: Connect) =>
      log.error(s"Failed to connect to $host:$port")
      context.stop(self)

    case Connected(remote, _) =>
      log.info(s"Connected to $remote")
      val connection = sender()
      connection ! Register(self)
      context.become(connected(connection))
  }

  def connected(connection: ActorRef): Receive = {
